prompt:
Examine:

struct TempSensor { virtual double celsius() = 0; };
struct VendorProbe { double readKelvin(); };
struct ProbeBridge : TempSensor {
  VendorProbe p;
  double celsius() override { return p.readKelvin() - 273.15; }
};

Which structural pattern does ProbeBridge implement?

Examine:

struct Channel { virtual void deliver(const std::string&) = 0; };
struct Email : Channel { void deliver(const std::string&) override; };
struct Sms : Channel { void deliver(const std::string&) override; };
struct Alert {
  Channel* ch;
  explicit Alert(Channel* c) : ch(c) {}
  virtual void raise(const std::string& m) { ch->deliver(format(m)); }
};
struct CriticalAlert : Alert { /* refined raise */ };

Which structural pattern is this?

Examine:

struct Task { virtual int hours() = 0; };
struct Chore : Task { int hours() override { return h; } };
struct Project : Task {
  std::vector<Task*> sub;
  int hours() override {
    int t = 0; for (auto* x : sub) t += x->hours(); return t;
  }
};

Which structural pattern is this?

Examine:

struct Report { virtual std::string body() = 0; };
struct PlainReport : Report { std::string body() override { return raw; } };
struct WatermarkLayer : Report {
  Report* inner;
  explicit WatermarkLayer(Report* r) : inner(r) {}
  std::string body() override { return inner->body() + "\n[CONFIDENTIAL]"; }
};

Which structural pattern does WatermarkLayer implement?

Examine:

struct MediaExport {
  Decoder dec; Resampler res; Encoder enc; Muxer mux;
  void run(const Clip& c) {
    auto frames = dec.decode(c);
    auto fixed  = res.normalize(frames);
    auto stream = enc.encode(fixed);
    mux.write(stream);
  }
};

Which structural pattern does MediaExport illustrate?

Examine:

struct Particle { Color color; Sprite sprite; void draw(float x, float y, float vx, float vy); };
struct ParticlePool {
  std::unordered_map<std::string, Particle*> kinds;
  Particle* get(const std::string& k) {
    auto it = kinds.find(k);
    if (it != kinds.end()) return it->second;
    return kinds[k] = new Particle(k);
  }
};

Given that position and velocity are passed to draw(), which structural pattern is this?

Examine:

struct Vault { virtual std::string read(int slot) = 0; };
struct GuardedVault : Vault {
  RealVault real; Session s;
  std::string read(int slot) override {
    if (!s.hasClearance(slot)) throw AccessDenied{};
    return real.read(slot);
  }
};

Which structural pattern is GuardedVault?

Examine:

struct Customer { /* domain entity */ };
struct CustomerStore {
  virtual std::optional<Customer> findById(int) = 0;
  virtual void save(const Customer&) = 0;
};
struct SqlCustomerStore : CustomerStore { /* SQL */ };
struct MemoryCustomerStore : CustomerStore { /* std::map */ };

What does this structure most directly demonstrate?

Study this code:

class Filter {
protected:
  Filter* next = nullptr;
public:
  void chain(Filter* n) { next = n; }
  virtual void process(Packet& p) { if (next) next->process(p); }
};
class DropSpam : public Filter {
  void process(Packet& p) override {
    if (p.isSpam()) return;        // stop here
    else Filter::process(p);       // forward
  }
};

Which pattern is shown?

Study this code:

struct Action { virtual void run() = 0; virtual void revert() = 0; };
struct AddRow : Action {
  Table& t;
  Row r;
  void run() override { t.insert(r); }
  void revert() override { t.remove(r); }
};
class Runner {
  std::vector<Action*> log;
public:
  void perform(Action* a) { a->run(); log.push_back(a); }
};

Which pattern is shown?

Study this code:

struct Term { virtual int eval(const Env& e) const = 0; };
struct Const : Term { int n; int eval(const Env&) const override { return n; } };
struct Mul : Term {
  const Term* l; const Term* r;
  int eval(const Env& e) const override { return l->eval(e) * r->eval(e); }
};

Which pattern is shown?

Study this code:

class RangeCursor {
  int current;
  int stop;
public:
  RangeCursor(int begin, int end) : current(begin), stop(end) {}
  bool done() const { return current >= stop; }
  int value() const { return current; }
  void advance() { ++current; }
};

Which pattern does RangeCursor embody?

Study this code:

class Tower;
class Plane {
  Tower* tower;
public:
  void requestLanding() { /* tower->coordinate(this) */ }
};
class Tower {
  std::vector<Plane*> planes;
public:
  void coordinate(Plane* requester) {
    /* decide order, tell other planes to hold */
  }
};

Planes interact only through Tower. Which pattern is shown?

Study this code:

class Canvas {
  std::vector<Stroke> strokes;
public:
  class Snapshot {
    friend class Canvas;
    std::vector<Stroke> saved;
    explicit Snapshot(std::vector<Stroke> s) : saved(std::move(s)) {}
  };
  Snapshot capture() const { return Snapshot(strokes); }
  void restore(const Snapshot& s) { strokes = s.saved; }
};

Which pattern is shown?

Study this code:

struct Watcher { virtual void onChange(double temp) = 0; };
class Thermostat {
  std::vector<Watcher*> watchers;
  double temp = 0;
public:
  void subscribe(Watcher* w) { watchers.push_back(w); }
  void setTemp(double t) { temp = t; for (auto* w : watchers) w->onChange(temp); }
};

Which pattern describes how Thermostat collaborates with its Watchers?

Study this code:

class Door;
struct DoorState { virtual void push(Door& d) = 0; };
struct Closed : DoorState { void push(Door& d) override; };
class Door {
  DoorState* state;
public:
  void setState(DoorState* s) { state = s; }
  void push() { state->push(*this); }
};
// Closed::push sets the door to an Open state

Which pattern does Door’s collaboration with DoorState demonstrate?

Study this code:

struct TaxRule { virtual double apply(double amount) const = 0; };
struct FlatTax : TaxRule { double apply(double a) const override { return a * 0.2; } };
class Invoice {
  const TaxRule* rule;
public:
  explicit Invoice(const TaxRule* r) : rule(r) {}
  double total(double net) const { return net + rule->apply(net); }
};

Which pattern does Invoice’s collaboration with TaxRule demonstrate?

Study this code:

class Report {
public:
  void build() { header(); body(); footer(); }
protected:
  void header() { /* fixed */ }
  void footer() { /* fixed */ }
  virtual void body() = 0;
};
class SalesReport : public Report {
  void body() override { /* sales rows */ }
};

Which pattern does build() demonstrate?

Study this code:

struct Circle; struct Rect;
struct ShapeOp {
  virtual void on(Circle&) = 0;
  virtual void on(Rect&) = 0;
};
struct Shape { virtual void accept(ShapeOp&) = 0; };
struct Circle : Shape { void accept(ShapeOp& op) override { op.on(*this); } };

Which pattern does the accept/on collaboration demonstrate?
